code = """import json
import os

# Load all the query results
results_1_path = locals()['var_functions.query_db:92']
results_2_path = locals()['var_functions.query_db:94']

all_results = []
for path in [results_1_path, results_2_path]:
    if os.path.exists(path):
        with open(path, 'r') as f:
            all_results.extend(json.load(f))

# Load stockinfo for company names
stockinfo_path = locals()['var_functions.query_db:56']
with open(stockinfo_path, 'r') as f:
    nyse_stocks = json.load(f)

symbol_to_name = {}
for stock in nyse_stocks:
    symbol = stock['Symbol']
    desc = stock['Company Description']
    name = desc.split(' specializes')[0].strip() if ' specializes' in desc else desc
    if symbol == 'AMT':
        name = "American Tower Corporation"
    symbol_to_name[symbol] = name

# Filter stocks with more up days than down days
winners = []
for row in all_results:
    symbol = row['symbol']
    up = row['up_days']
    down = row['down_days']
    total = row['total_days']
    
    if total > 0 and up != 'nan' and down != 'nan':
        up_days = float(up)
        down_days = float(down)
        if up_days > down_days:
            winners.append({
                'symbol': symbol,
                'name': symbol_to_name.get(symbol, symbol),
                'up_days': int(up_days),
                'down_days': int(down_days),
                'net': int(up_days - down_days)
            })

# Sort by net advantage
winners_sorted = sorted(winners, key=lambda x: x['net'], reverse=True)

top_5 = winners_sorted[:5]
print('__RESULT__:')
print(json.dumps(top_5))"""

